use std::collections::HashMap;

struct BuildSystem {
    dependencies: HashMap<String, Vec<String>>,
}

impl BuildSystem {
    fn new() -> Self {
        BuildSystem { dependencies: HashMap::new() }
    }

    fn track_dependency(&mut self, component: &str, file_paths: &[&str]) {
        let key = format!("{}", component);
        let deps = self.dependencies.entry(key.to_string()).or_default();
        let joined_path = file_paths.join("/");
        deps.push(joined_path);
    }

    fn display_all(&self) -> String {
        let mut output = String::new();
        for (component, paths) in &self.dependencies {
            output.push_str(&format!("Component: {}n", component));
            for path in paths {
                output.push_str(&format!("  - {}n", path));
            }
        }
        output
    }
}

fn main() {
    let mut build = BuildSystem::new();

    build.track_dependency("AppRoot", &["src/main.rs", "src/config.ts"]);
    build.track_dependency("UtilsLib", &["utils/math.rs", "utils/strings.rs"]);
    build.track_dependency("ClientView", &["client/index.tsx"]);

    println!("n--- Build Dependency Map ---");
    println!("{}", build.display_all());
}

use std::collections::HashMap;

struct SourceMapEntry {
    original_line: String,
    transformed_value: String,
}

fn process_log_data(input_text: &str) -> HashMap<String, Vec<SourceMapEntry>> {
    let mut source_map: HashMap<String, Vec<SourceMapEntry>> = HashMap::new();

    for line in input_text.lines() {
        if let Some((key, value)) = line.split_once(":s*") {
            let key_str = key.trim().to_string();
            let value_str = value.trim().to_string();

            let entry = SourceMapEntry {
                original_line: line.to_string(),
                transformed_value: value_str,
            };

            source_map.entry(key_str)
                .or_insert_with(Vec::new)
                .push(entry);
        }
    }
    source_map
}

use std::collections::HashMap;

struct AuthTokenProcessor {
    data: HashMap<String, Vec<String>>,
}

impl AuthTokenProcessor {
    fn new() -> Self {
        AuthTokenProcessor { data: HashMap::new() }
    }

    fn add_token_set(&mut self, key: &str, comma_separated_string: &str) {
        let tokens: Vec<String> = comma_separated_string.split(',')
            .map(|s| s.trim().to_owned())
            .collect();

        self.data.insert(key.to_owned(), tokens);
    }

    fn process_all(&self) -> HashMap<String, Vec<String>> {
        self.data.clone()
    }
}

fn main() {
    let mut processor = AuthTokenProcessor::new();

    processor.add_token_set("key_id", "fido2-device1,webauthn-primary");
    processor.add_token_set("user_data", "alice@example.com,admin_role");

    let final_map = processor.process_all();

    for (key, tokens) in final_map.iter() {
        println!("Processing key: {}", key);
        for token in tokens {
            println!("  -> Found token: ");
            println!("     {}", token);
        }
    }
}

use std::collections::HashMap;

struct AssignmentList {
    assignments: HashMap<String, i32>,
}

impl AssignmentList {
    fn parse_string(data: &str) -> Result<Self, String> {
        let mut assignments = HashMap::new();
        let pairs = data.split(',');

        for pair in pairs {
            let parts: Vec<&str> = pair.trim().split('=').collect();
            if parts.len() != 2 {
                return Err(format!("Invalid pair format: {}", pair));
            }
            let key = parts[0].to_string();
            let value_str = parts[1].trim();
            match value_str.parse::<i32>() {
                Ok(value) => {
                    assignments.insert(key, value);
                },
                Err(_) => {
                    return Err(format!("Cannot parse integer for key '{}': {}", key, value_str));
                }
            }
        }

        Ok(AssignmentList { assignments })
    }

    fn get_value(&self, key: &str) -> Option<i32> {
        self.assignments.get(key).copied()
    }
}

fn main() {
    let raw_data = "variableA=10, variableB=5, finalValue=99";
    match AssignmentList::parse_string(raw_data) {
        Ok(list) => {
            println!("Successfully parsed assignments.");
            if let Some(val) = list.get_value("variableB") {
                println!("Value for variableB: {}", val);
            }
        },
        Err(e) => {
            eprintln!("Parsing error: {}", e);
        }
    }
}

use std::collections::HashMap;

struct ConfigManager {
    settings: HashMap<String, String>,
}

impl ConfigManager {
    fn new() -> Self {
        ConfigManager { settings: HashMap::new() }
    }

    fn set_from_csv(&mut self, csv_string: &str) -> Result<(), String> {
        let keys: Vec<&str> = csv_string.split(',').collect();
        if keys.is_empty() {
            return Err("Input string was empty".to_string());
        }

        for key in keys {
            if key.trim().is_empty() {
                continue;
            }
            self.settings.insert(key.trim().to_string(), "default_value".to_string());
        }
        Ok(())
    }

    fn get_all_keys_as_csv(&self) -> String {
        let mut keys: Vec<String> = self.settings.keys().cloned().collect();
        keys.sort();
        keys.join(",")
    }
}

fn main() {
    let mut manager = ConfigManager::new();
    let input_csv = "database,network,logging";

    if let Err(e) = manager.set_from_csv(input_csv) {
        println!("Error setting config: {}", e);
        return;
    }

    println!("Successfully loaded keys from: {}", input_csv);
    let output_csv = manager.get_all_keys_as_csv();
    println!("Auto-formatted key list (sorted): {}", output_csv);
}
